class Solution(object):
    def answerString(self, word, numFriends):
        if numFriends == 1:
            return word
        n = len(word)
        # Max substring length is n - numFriends + 1
        max_len = n - numFriends + 1
        best = ""
        for i in range(n):
            candidate = word[i:i + max_len]
            if candidate > best:
                best = candidate
        return best
